```class Solution {
public:
    int maxVowels(string s, int k) {
        vector<int> count(5, 0); // Initialize a vector to store the count of vowels
        for (int i = 0; i < s.length(); i++) {
            if (s[i] == 'a' || s[i] == 'e' || s[i] == 'i' || s[i] == 'o' || s[i] == 'u') {
                count[s[i] - 'a']++; // Increment the count of the corresponding vowel
            }
        }
        int result = 0;
        for (int i = 0; i < k && i < s.length(); i++) {
            result = max(result, count[s[i] - 'a']);
            for (int j = 0; j < k && j < s.length(); j++) {
                result = max(result, count[s[j] - 'a'];
            }
        }
        return result;
    }
};
```

